SELECT message_id, room_id, sender_id, sender_name, content, sent_at, company_id,
       message_type, file_url, file_name, is_deleted, is_edited
FROM chat_message
WHERE room_id = #{roomId}
  AND company_id = #{companyId}
ORDER BY sent_at DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM chat_message m
WHERE m.room_id = #{roomId}
  AND m.company_id = #{companyId}
  AND m.sender_id != #{employeeId}
  AND m.sent_at > COALESCE(
      (SELECT last_read_at FROM chat_read
       WHERE room_id = #{roomId} AND employee_id = #{employeeId}),
      '1970-01-01')

SELECT employeeId, emp_nm, position, deptName
FROM employee
WHERE active = 1
  AND company_id = #{companyId}
  AND employeeId != #{myId}
ORDER BY emp_nm
